// Noncompliant: Using 'unsafe-inline' allows inline scripts
app.Use(async (context, next) =>
{
    context.Response.Headers.Add("Content-Security-Policy", "default-src 'self'; script-src 'self' 'unsafe-inline'");
    await next();
});

// Noncompliant: Too permissive with wildcard
app.Use(async (context, next) =>
{
    context.Response.Headers.Add("Content-Security-Policy", "default-src *");
    await next();
});

compliant:
// Compliant: Restrictive CSP without unsafe directives
app.Use(async (context, next) =>
{
    context.Response.Headers.Add("Content-Security-Policy", "default-src 'self'; script-src 'self'; style-src 'self'; img-src 'self' data:");
    await next();
});

// Compliant: Using nonce for inline scripts
app.Use(async (context, next) =>
{
    var nonce = Convert.ToBase64String(RandomNumberGenerator.GetBytes(16));
    context.Response.Headers.Add("Content-Security-Policy", $"default-src 'self'; script-src 'self' 'nonce-{nonce}'");
    await next();
});
